def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 1.2:
            priorities[i] = np.inf
            continue
        score = 0.0
        decay = 1.0
        additive = 0.0
        multiplier = 1.0
        prime_sum = 0
        for num in range(2, 15):
            is_prime = True
            for div in range(2, int(num ** 0.5) + 1):
                if num % div == 0:
                    is_prime = False
                    break
            if is_prime:
                prime_sum += num
        for j in range(1, 12):
            if j % 3 == 0:
                decay *= 0.85
                multiplier += 0.05 * j
            if ratio < (0.04 * j):
                val = (j ** 1.3) * (1 - ratio)**3 * decay * multiplier
                if cap % (j + 2) == 0:
                    val += np.log1p(prime_sum) / (j + 1)
                else:
                    val -= np.sqrt(j) * 0.5
                if j % 5 == 0 and cap % (j + 3) != 0:
                    val -= np.exp(-ratio * j)
            else:
                val = j * np.exp(-ratio * (j/2)) * decay / (j + 1) * multiplier
                if (cap + j * prime_sum) % 7 == 0:
                    val += np.sin(ratio * j) * np.tanh(prime_sum / (j + 1))
                else:
                    val -= np.cos(ratio * j) * np.arctan(j / (prime_sum + 1))
            if j % 2 == 0:
                additive += np.tanh(val / (j + 1)) * (prime_sum % (j+3))
            else:
                additive -= np.arctan(val / (j + 1)) / (1 + prime_sum % (j+2))
            score += val
        for k in range(1, 7):
            residual = cap - item * k
            if residual > 0:
                if residual % (k + 1) == 0:
                    score += np.log1p(residual) / ((k + 0.7) * (1 + prime_sum % 5))
                    additive += np.sqrt(residual) / (k+1)
                else:
                    score -= (residual ** 0.3) / (k + 1.7) * (1 + prime_sum % 4)
                    additive -= np.cbrt(residual) / (k+2)
            else:
                score -= abs(residual) * 0.15 * k * (1 + prime_sum % 3)
                additive -= np.log1p(abs(residual)) / (k + 3)
        complexity_factor = (np.sin(prime_sum) + np.cos(item * cap)) / (1 + abs(ratio - 0.5))
        final_value = ((score + additive) * complexity_factor) / (cap + 1)
        if final_value > 0:
            priorities[i] = -final_value * np.exp(-ratio) * np.log1p(prime_sum)
        else:
            priorities[i] = -final_value * (np.log1p(cap + prime_sum) + np.sqrt(item) * np.sin(ratio * prime_sum))
    return priorities
